const STRUCTURE = (() => {
  const rows = Object.values(DATASETS).flat().filter(Boolean);
  const map = new Map();
  const largeOf = x => x.law || x.largeGroup || x.largeUnit || x.subject || "기타";
  const smallOf = x => x.smallUnit || x.unit || x.category || "공통";
  for (const x of rows) {
    const large = largeOf(x);
    const small = smallOf(x);
    if (!map.has(large)) map.set(large, new Map());
    map.get(large).set(small, (map.get(large).get(small) || 0) + 1);
  }
  return Array.from(map.entries()).map(([name, childMap]) => ({
    name,
    count: Array.from(childMap.values()).reduce((a,b)=>a+b,0),
    children: Array.from(childMap.entries()).map(([name,count])=>({name,count}))
  }));
})();

const LABELS = {must:"⭐ 반드시", study:"🃏 암기카드", years:"📅 기간별", ox:"OX", fill:"빈칸", all:"전체", wrong:"오답", fav:"별표"};
const examDate = new Date("2026-10-31T00:00:00+09:00");
let currentTab = "must";
let selectedLarge = "";
let selectedSmall = "";
let search = "";
let allData = [];
const favs = new Set(JSON.parse(localStorage.getItem("deunggi_favs_v1") || "[]"));
const wrongs = new Set(JSON.parse(localStorage.getItem("deunggi_wrongs_v1") || "[]"));
let masterCounts = JSON.parse(localStorage.getItem("deunggi_master_counts_v1") || "{}");

function esc(s) {
  return String(s ?? "").replace(/[&<>"']/g, m => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[m]));
}
function normalize(s) {
  return String(s ?? "")
    .replace(/정답|뒷면|앞면/g,"")
    .replace(/[①②③④⑤⑥⑦⑧⑨⑩]/g,"")
    .replace(/[\s,./;:|()\[\]{}·㎡원]/g,"")
    .toLowerCase();
}
function candidates(item) {
  const vals = [item.answer, item.allowed].filter(Boolean).join(",");
  const parts = vals.split(/[\n,;/]| 또는 | 혹은 |\/|·/).map(x => x.trim()).filter(Boolean);
  const set = new Set();
  for (const p of parts) {
    set.add(normalize(p));
    p.split(/\s+/).forEach(t => { if (t) set.add(normalize(t)); });
  }
  set.add(normalize(vals));
  return [...set].filter(Boolean);
}
function baseList() {
  if (currentTab === "all") return allData;
  if (currentTab === "fav") return allData.filter(x => favs.has(x.id));
  if (currentTab === "wrong") return allData.filter(x => wrongs.has(x.id));
  return DATASETS[currentTab] || [];
}
function match(item) {
  const text = [item.largeUnit,item.smallUnit,item.category,item.type,item.title,item.question,item.answer,item.allowed,item.explanation,item.memory,item.trap,item.source,...(item.tags||[])].join(" ").toLowerCase();
  if (selectedLarge && item.largeUnit !== selectedLarge) return false;
  if (selectedSmall && item.smallUnit !== selectedSmall) return false;
  if (search && !text.includes(search.toLowerCase())) return false;
  return true;
}
function setTab(tab) { currentTab = tab; render(); }
function selectUnit(large, small="") { selectedLarge = large || ""; selectedSmall = small || ""; render(); }
function clearUnit() { selectedLarge = ""; selectedSmall = ""; render(); }
function saveState() {
  localStorage.setItem("deunggi_favs_v1", JSON.stringify([...favs]));
  localStorage.setItem("deunggi_wrongs_v1", JSON.stringify([...wrongs]));
  localStorage.setItem("deunggi_master_counts_v1", JSON.stringify(masterCounts));
}
function renderTabs() {
  const tabs = ["must","study","years","ox","fill","all","wrong","fav"];
  document.getElementById("tabs").innerHTML = tabs.map(t=>`<button class="${currentTab===t?'active':''}" onclick="setTab('${t}')">${LABELS[t]}</button>`).join("");
}
function masterCountForUnit(large, small="") {
  return allData
    .filter(x => x.largeUnit === large && (!small || x.smallUnit === small))
    .reduce((sum, x) => sum + ((Number(masterCounts[x.id]) || 0) > 0 ? 1 : 0), 0);
}
function markMastered(id) {
  if ((Number(masterCounts[id]) || 0) > 0) delete masterCounts[id];
  else masterCounts[id] = 1;
  saveState();
  renderFolders();
  renderCards();
}
function renderFolders() {
  const strip = document.getElementById("folderStrip");
  strip.innerHTML = `<button class="folder-chip ${!selectedLarge?'on':''}" onclick="clearUnit()">전체 단원</button>` +
    STRUCTURE.map(u=>`<button class="folder-chip ${selectedLarge===u.name&&!selectedSmall?'on':''}" onclick="selectUnit('${esc(u.name)}')">${esc(u.name)} · ${u.count}개 ㅡ 완전암기 ${masterCountForUnit(u.name)}/${u.count}</button>`).join("");
  const tree = document.getElementById("tree");
  tree.innerHTML = STRUCTURE.map(u=>`
    <div class="tree-section">
      <button class="tree-head ${selectedLarge===u.name&&!selectedSmall?'on':''}" onclick="selectUnit('${esc(u.name)}')">
        <span>${esc(u.name)}</span><span>${masterCountForUnit(u.name)}/${u.count}</span>
      </button>
      <div class="tree-child">
        ${(u.children||[]).map(c=>`<button class="${selectedSmall===c.name?'on':''}" onclick="selectUnit('${esc(u.name)}','${esc(c.name)}')">${esc(c.name)} · ${c.count}개 ㅡ 완전암기 ${masterCountForUnit(u.name,c.name)}/${c.count}</button>`).join("")}
      </div>
    </div>`).join("");
}
function toggleFav(id) { favs.has(id)?favs.delete(id):favs.add(id); saveState(); renderCards(); renderStats(); }
function toggleWrong(id) { wrongs.has(id)?wrongs.delete(id):wrongs.add(id); saveState(); renderCards(); renderStats(); }
function checkQuiz(id, value=null) {
  const item = allData.find(x=>x.id===id);
  if (!item) return;
  const input = document.getElementById(`answer-${id}`);
  const result = document.getElementById(`result-${id}`);
  const user = String(value ?? (input ? input.value : "")).trim();
  if (!user) {
    result.textContent = "정답을 입력하거나 선택해.";
    result.className = "quiz-result warn";
    return;
  }
  let ok = false;
  if (item.type === "OX") ok = normalize(user) === normalize(item.answer);
  else {
    const n = normalize(user);
    ok = candidates(item).some(c => c === n || c.includes(n) || n.includes(c));
  }
  if (ok) {
    result.textContent = "정답 ✅";
    result.className = "quiz-result correct";
  } else {
    result.textContent = "오답 ❌  정답: " + item.answer;
    result.className = "quiz-result wrong";
    wrongs.add(id);
    saveState();
    renderStats();
  }
}
function quizBox(item) {
  if (!["ox","fill"].includes(currentTab)) return "";
  if (item.type === "OX") {
    return `<div class="quiz-box"><div class="quiz-title">직접 풀기</div><div class="quiz-actions"><button onclick="checkQuiz('${item.id}','O')">O</button><button onclick="checkQuiz('${item.id}','X')">X</button></div><div id="result-${item.id}" class="quiz-result"></div></div>`;
  }
  return `<div class="quiz-box"><div class="quiz-title">직접 풀기</div><input id="answer-${item.id}" class="quiz-input" placeholder="정답 입력" onkeydown="if(event.key==='Enter') checkQuiz('${item.id}')" /><button class="quiz-check" onclick="checkQuiz('${item.id}')">채점</button><div id="result-${item.id}" class="quiz-result"></div></div>`;
}
function visibleBlock(label, content, className="extra") {
  if (!content) return "";
  return `<div class="${className}"><strong>${label}</strong><br>${esc(content)}</div>`;
}
function memoryCard(item, rowIdx, kindLabel="") {
  const done = (Number(masterCounts[item.id]) || 0) > 0;
  return `
    <article class="memory-card ${done ? "done" : ""}">
      <div class="memory-top">
        <span class="memory-no">${rowIdx + 1}</span>
        <div>
          <div class="memory-title">${esc(item.title)}</div>
          <div class="memory-meta">${esc(kindLabel || item.category || "")} · ${esc(item.level || "")}</div>
        </div>
      </div>
      <div class="memory-section">
        <div class="memory-label">공부내용</div>
        <div class="memory-content">${esc(item.answer || item.question || "-")}</div>
      </div>
      ${item.memory ? `<div class="memory-section point"><div class="memory-label">암기포인트</div><div class="memory-content">${esc(item.memory)}</div></div>` : ""}
      ${item.trap ? `<div class="memory-section trap-card"><div class="memory-label">함정</div><div class="memory-content">${esc(item.trap)}</div></div>` : ""}
      <div class="memory-actions">
        <button class="small mastered ${done ? 'on' : ''}" onclick="markMastered('${item.id}')">${done ? '↺ 까먹음 처리' : '✓ 완전외움'}</button>
      </div>
    </article>`;
}
function renderGroupedCards(rows, emptyMsg, label) {
  const box = document.getElementById("cards");
  if (!rows.length) {
    box.innerHTML = `<div class="empty">${emptyMsg}</div>`;
    return;
  }
  const groups = {};
  for (const item of rows) {
    const key = `${item.largeUnit}|||${item.smallUnit}`;
    if (!groups[key]) groups[key] = [];
    groups[key].push(item);
  }
  box.innerHTML = Object.entries(groups).map(([key, items], idx) => {
    const [large, small] = key.split("|||");
    const cards = items.map((item, rowIdx) => memoryCard(item, rowIdx, label)).join("");
    return `<details class="memory-unit" ${idx === 0 ? "open" : ""}>
      <summary><span>${esc(large)} ㅡ ${esc(small)}</span><b>${masterCountForUnit(large, small)}/${items.length}</b></summary>
      <div class="memory-list">${cards}</div>
    </details>`;
  }).join("");
}
function renderStudyCards() {
  renderGroupedCards((DATASETS.study || []).filter(match), "암기카드 데이터가 없습니다.", "암기카드");
}
function renderPeriodCards() {
  renderGroupedCards((DATASETS.years || []).filter(match), "기간별 데이터가 없습니다.", "기간·숫자");
}
function renderVisibleStudyCard(item) {
  const isStudyContent = currentTab === "must";
  return `
    <article class="card">
      <div class="badge-row">
        <span class="badge unit">${esc(item.largeUnit)}</span>
        <span class="badge unit">${esc(item.smallUnit)}</span>
        <span class="badge type">${esc(item.category)}</span>
        <span class="badge type">${esc(item.type || "")}</span>
        <span class="badge hot">${esc(item.level || "")}</span>
      </div>
      <div class="title">${esc(item.title)}</div>
      ${isStudyContent ? `<div class="answer visible-answer">${esc(item.answer || "")}</div>` : `<div class="question">${esc(item.question)}</div>`}
      ${isStudyContent && item.memory ? visibleBlock("암기포인트", item.memory, "extra visible-note") : ""}
      ${isStudyContent && item.trap ? visibleBlock("함정", item.trap, "extra trap visible-note") : ""}
      ${!isStudyContent ? quizBox(item) : ""}
      ${!isStudyContent ? `<details><summary>정답/해설 보기</summary><div class="answer">${esc(item.answer)}${item.explanation ? "\n\n" + esc(item.explanation) : ""}</div></details>` : ""}
      ${!isStudyContent && item.trap ? `<details><summary>함정 보기</summary><div class="extra trap">${esc(item.trap)}</div></details>` : ""}
      <div class="card-actions">
        <button class="small mastered ${(Number(masterCounts[item.id]) || 0) > 0 ? 'on' : ''}" onclick="markMastered('${item.id}')">${(Number(masterCounts[item.id]) || 0) > 0 ? '↺ 까먹음 처리' : '✓ 완전외움'}</button>
        <button class="small wrong ${wrongs.has(item.id)?'on':''}" onclick="toggleWrong('${item.id}')">✕ 오답</button>
        <button class="small fav ${favs.has(item.id)?'on':''}" onclick="toggleFav('${item.id}')">★ 별표</button>
      </div>
    </article>`;
}
function renderCards() {
  if (currentTab === "study") return renderStudyCards();
  if (currentTab === "years") return renderPeriodCards();
  const list = baseList().filter(match);
  const box = document.getElementById("cards");
  if (!list.length) {
    box.innerHTML = `<div class="empty">데이터가 없습니다. 단원 선택이나 검색어를 초기화해봐.</div>`;
    return;
  }
  box.innerHTML = list.map(item => renderVisibleStudyCard(item)).join("");
}
function renderStats() {
  document.getElementById("mustCount").textContent = DATASETS.must.length;
  document.getElementById("cardCount").textContent = DATASETS.study.length;
  document.getElementById("quizCount").textContent = DATASETS.ox.length + DATASETS.fill.length;
  document.getElementById("wrongCount").textContent = wrongs.size;
}
function renderDday() {
  const diff = Math.ceil((examDate - new Date())/(1000*60*60*24));
  document.getElementById("dday").textContent = diff >= 0 ? `D-${diff}` : `D+${Math.abs(diff)}`;
}
function render() { renderTabs(); renderFolders(); renderCards(); renderStats(); renderDday(); }
document.addEventListener("DOMContentLoaded", () => {
  allData = Object.entries(DATASETS).flatMap(([k,arr]) => arr.map(x => ({...x, dataGroup:k})));
  const memo = document.getElementById("memo");
  memo.value = localStorage.getItem("deunggi_memo_v1") || "";
  memo.addEventListener("input", () => localStorage.setItem("deunggi_memo_v1", memo.value));
  document.getElementById("searchInput").addEventListener("input", e => { search = e.target.value.trim(); renderCards(); });
  document.getElementById("resetBtn").addEventListener("click", () => {
    search = ""; selectedLarge = ""; selectedSmall = ""; currentTab = "must";
    document.getElementById("searchInput").value = "";
    render();
  });
  render();
});
